// ============================================================
// GENERATE SUMMARY AFTER BATCH UPDATE
// Đặt node này SAU Batch Update
// ============================================================

const items = $input.all();

const summary = {
    timestamp: new Date().toISOString(),
    total_updated: items.length,
    healthy: items.filter(i => i.json.health_status === 'healthy').length,
    degraded: items.filter(i => i.json.health_status === 'degraded').length,
    disabled: items.filter(i => i.json.health_status === 'disabled').length,
    failed_keys: items
        .filter(i => i.json.health_status !== 'healthy')
        .map(i => ({
            key_id: i.json.key_id,
            status: i.json.health_status,
            failures: i.json.health_check_failures,
            error: i.json.error_code
        }))
};

console.log('=== HEALTH CHECK SUMMARY ===');
console.log(JSON.stringify(summary, null, 2));

// Trả về items gốc để tiếp tục batch update
return { summary };

// === HEALTH CHECK LOGIC v2.0 – PARSE RATE LIMIT HEADERS ===

function getVietnamTime(date) {
    const d = date || new Date();
    const vietnamTime = new Date(d.getTime() + (7 * 60 * 60 * 1000));
    const year = vietnamTime.getUTCFullYear();
    const month = String(vietnamTime.getUTCMonth() + 1).padStart(2, '0');
    const day = String(vietnamTime.getUTCDate()).padStart(2, '0');
    const hours = String(vietnamTime.getUTCHours()).padStart(2, '0');
    const minutes = String(vietnamTime.getUTCMinutes()).padStart(2, '0');
    const seconds = String(vietnamTime.getUTCSeconds()).padStart(2, '0');
    return `${year}-${month}-${day} ${hours}:${minutes}:${seconds}`;
}

const keyData = $('Get Fail Keys').item.json;
const checkResult = $('Check Gemini').item.json;   // full response

const now = getVietnamTime();

let result = {
    key_id: keyData.key_id,
    last_checked_at: now,
    last_quota_check_at: now
};

// ============================================================
// PARSE HEADERS + BODY (mới)
// ============================================================
const headers = checkResult.headers || checkResult.response?.headers || {};
const body = checkResult.body || checkResult || {};

const httpStatus = checkResult.statusCode || checkResult.status || 0;

// === PARSE RATE LIMIT HEADERS ===
const rl = {
    remaining_requests: parseInt(headers['x-ratelimit-remaining-requests'] || headers['X-RateLimit-Remaining'] || 0),
    remaining_tokens: parseInt(headers['x-ratelimit-remaining-tokens'] || 0),
    reset_requests: headers['x-ratelimit-reset-requests'] || '',
    reset_tokens: headers['x-ratelimit-reset-tokens'] || '',
    retry_after: parseInt(headers['retry-after'] || 0)
};

result.remaining_requests = rl.remaining_requests;
result.remaining_tokens = rl.remaining_tokens;
result.quota_reset_requests_at = rl.reset_requests;
result.quota_reset_tokens_at = rl.reset_tokens;
result.retry_after = rl.retry_after;

// ============================================================
// STEP 2: Classify error type and determine response
// ============================================================
// ERROR CLASSIFICATION TABLE (from Gemini API docs):
// ┌──────────┬──────────────────────────┬───────────────┬──────────────────────────┐
// │ HTTP     │ gRPC Status              │ Key's Fault?  │ Response                 │
// ├──────────┼──────────────────────────┼───────────────┼──────────────────────────┤
// │ 200      │ OK                       │ -             │ ✅ Healthy               │
// │ 400      │ INVALID_ARGUMENT         │ ❌ No         │ 🟡 Degraded (transient)  │
// │ 403      │ PERMISSION_DENIED        │ ✅ Yes        │ 🔴 Block 24h            │
// │ 404      │ NOT_FOUND                │ ❌ No         │ 🟡 Ignore (model issue)  │
// │ 429      │ RESOURCE_EXHAUSTED       │ ✅ Yes        │ 🔴 Block (timed)         │
// │ 500      │ INTERNAL                 │ ❌ No         │ 🟡 Degraded (transient)  │
// │ 503      │ UNAVAILABLE              │ ❌ No         │ 🟡 Degraded (transient)  │
// └──────────┴──────────────────────────┴───────────────┴──────────────────────────┘

// Extract gRPC status if available
const grpcStatus = body?.error?.status || '';

// Extract error message
let errorMessage = '';
if (checkResult?.error) {
    const err = checkResult.error;
    errorMessage = err.message || err.error?.message || (typeof err === 'string' ? err : JSON.stringify(err).substring(0, 300));
} else if (body?.error) {
    const err = body.error;
    errorMessage = err.message || JSON.stringify(err).substring(0, 300);
}

const hasModels = body?.models && Array.isArray(body.models) && body.models.length > 0;

let errorType = 'UNKNOWN';
let action = 'degraded';    // Default: mark as degraded
let blockMinutes = 0;
let isKeyFault = false;     // Whether the error is caused by the key itself

// ---- Check for Rate Limit / Quota (429 RESOURCE_EXHAUSTED) ----
const isRateLimit = httpStatus === 429 ||
    grpcStatus === 'RESOURCE_EXHAUSTED' ||
    errorMessage.toLowerCase().includes('resource exhausted') ||
    errorMessage.toLowerCase().includes('rate limit') ||
    errorMessage.toLowerCase().includes('quota exceeded') ||
    errorMessage.toLowerCase().includes('spacing your requests') ||
    errorMessage.toLowerCase().includes('too many requests');

if (httpStatus === 200 && hasModels) {
    // ✅ KEY IS HEALTHY
    action = 'healthy';
    console.log(`✅ ${keyData.key_id}: HEALTHY`);

} else if (isRateLimit) {
    // 🔴 429 RESOURCE_EXHAUSTED — Most dangerous error
    errorType = 'RATE_LIMIT_429';
    action = 'block';
    isKeyFault = true;

    // Determine block duration based on error message
    if (errorMessage.toLowerCase().includes('per day') || errorMessage.toLowerCase().includes('daily')) {
        blockMinutes = 720; // 12 hours max
        console.log(`🔴 ${keyData.key_id}: DAILY QUOTA EXHAUSTED → block 12h`);
    } else {
        blockMinutes = 15; // 15 minutes
        console.log(`🔴 ${keyData.key_id}: RATE LIMITED (RPM/TPM) → block 15min`);
    }

} else if (httpStatus === 403 || grpcStatus === 'PERMISSION_DENIED') {
    // 🔴 403 PERMISSION_DENIED
    errorType = 'PERMISSION_DENIED_403';
    action = 'block';
    isKeyFault = true;
    blockMinutes = 1440; // 24 hours
    console.log(`🚫 ${keyData.key_id}: PERMISSION DENIED → block 24h`);

} else if (httpStatus === 401 || grpcStatus === 'UNAUTHENTICATED') {
    // 🔴 401 UNAUTHENTICATED
    errorType = 'UNAUTHENTICATED_401';
    action = 'disable';
    isKeyFault = true;
    console.log(`❌ ${keyData.key_id}: INVALID/EXPIRED KEY → disabled`);

} else if (httpStatus === 404 || grpcStatus === 'NOT_FOUND') {
    // 🟢 404 NOT_FOUND — Not key issue
    errorType = 'NOT_FOUND_404';
    action = 'ignore';
    console.log(`ℹ️ ${keyData.key_id}: Model not found (not key issue)`);

} else if (httpStatus === 400 || grpcStatus === 'INVALID_ARGUMENT' || grpcStatus === 'FAILED_PRECONDITION') {
    // 🟡 400 INVALID_ARGUMENT
    errorType = 'BAD_REQUEST_400';

    if (errorMessage.toLowerCase().includes('billing') || errorMessage.toLowerCase().includes('free tier') || errorMessage.toLowerCase().includes('not available')) {
        action = 'block';
        isKeyFault = true;
        blockMinutes = 1440;
        console.log(`🔴 ${keyData.key_id}: BILLING/REGION ISSUE → block 24h`);
    } else {
        action = 'ignore';
        console.log(`ℹ️ ${keyData.key_id}: BAD REQUEST (not key issue)`);
    }

} else if (httpStatus === 500 || grpcStatus === 'INTERNAL') {
    // 🟡 500 INTERNAL
    errorType = 'SERVER_ERROR_500';
    action = 'degraded';
    console.log(`🟡 ${keyData.key_id}: SERVER ERROR 500 (transient, not key fault)`);

} else if (httpStatus === 503 || grpcStatus === 'UNAVAILABLE') {
    // 🟡 503 UNAVAILABLE
    errorType = 'UNAVAILABLE_503';
    action = 'degraded';
    console.log(`🟡 ${keyData.key_id}: SERVICE UNAVAILABLE 503 (transient, not key fault)`);

} else if (httpStatus === 0 || !httpStatus) {
    // Network error
    errorType = 'NETWORK_ERROR';
    action = 'degraded';
    console.log(`🟡 ${keyData.key_id}: NETWORK ERROR (couldn't reach API)`);

} else {
    // Unknown error code
    errorType = `UNKNOWN_${httpStatus}`;
    action = 'degraded';
    console.log(`❓ ${keyData.key_id}: UNKNOWN ERROR (HTTP ${httpStatus})`);
}

// ============================================================
// STEP 3: Apply action to key state
// ============================================================\nconst currentConsecutiveFailures = parseInt(keyData.consecutive_failures || 0);
const currentHealthCheckFailures = parseInt(keyData.health_check_failures || 0);

if (action === 'healthy') {
    result.health_status = 'healthy';
    result.last_success_at = now;
    result.health_check_failures = 0;
    result.consecutive_failures = 0;
    result.is_active = true;
    result.error_code = '';
    result.blocked_until = '';

} else if (action === 'block') {
    const blockedUntilDate = new Date(new Date().getTime() + blockMinutes * 60 * 1000);
    result.health_status = errorType.includes('RATE_LIMIT') ? 'rate_limited' : 'blocked';
    result.is_active = false;
    result.consecutive_failures = currentConsecutiveFailures + 1;
    result.health_check_failures = currentHealthCheckFailures + 1;
    result.last_failure_at = now;
    result.error_code = `${errorType}: ${errorMessage.substring(0, 200)}`;
    result.blocked_until = getVietnamTime(blockedUntilDate);
    console.log(`   → blocked_until: ${result.blocked_until}`);

} else if (action === 'disable') {
    result.health_status = 'disabled';
    result.is_active = false;
    result.consecutive_failures = currentConsecutiveFailures + 1;
    result.health_check_failures = currentHealthCheckFailures + 1;
    result.last_failure_at = now;
    result.error_code = `${errorType}: ${errorMessage.substring(0, 200)}`;
    result.blocked_until = '';

} else if (action === 'ignore') {
    result.health_status = keyData.health_status || 'healthy';
    result.is_active = keyData.is_active;
    result.consecutive_failures = currentConsecutiveFailures;
    result.health_check_failures = currentHealthCheckFailures;
    result.error_code = `${errorType}: ${errorMessage.substring(0, 200)}`;
    result.blocked_until = keyData.blocked_until || '';

} else {
    // action === 'degraded'
    const MAX_DEGRADED_FAILURES = 5;
    result.consecutive_failures = currentConsecutiveFailures + 1;
    result.health_check_failures = currentHealthCheckFailures + 1;
    result.last_failure_at = now;
    result.error_code = `${errorType}: ${errorMessage.substring(0, 200)}`;

    if (result.consecutive_failures >= MAX_DEGRADED_FAILURES) {
        result.is_active = false;
        result.health_status = 'degraded_disabled';
        result.blocked_until = '';
        console.log(`🔴 ${keyData.key_id}: ${result.consecutive_failures} transient errors → disabled`);
    } else {
        result.is_active = keyData.is_active !== undefined ? keyData.is_active : true;
        result.health_status = 'degraded';
        result.blocked_until = keyData.blocked_until || '';
        console.log(`🟡 ${keyData.key_id}: ${result.consecutive_failures}/${MAX_DEGRADED_FAILURES} transient errors`);
    }
}

// Bổ sung quota từ header cho healthy/degraded status
if (action === 'healthy' || action === 'degraded') {
    if (result.health_status === 'healthy' || result.health_status === 'degraded') {
        // (Quota fields đã được thêm vào result object ở đầu script)
    }
}

return { json: result };

// === UNIVERSAL API KEY ROTATOR v2.0 – FULL RATE LIMIT HEADERS ===
// Tích hợp proactive quota tracking + improved sorting

// ============================================================
// VIETNAM TIMEZONE HELPERS
// ============================================================
function getVietnamTime(date) {
    const d = date || new Date();
    const vietnamTime = new Date(d.getTime() + (7 * 60 * 60 * 1000));
    const year = vietnamTime.getUTCFullYear();
    const month = String(vietnamTime.getUTCMonth() + 1).padStart(2, '0');
    const day = String(vietnamTime.getUTCDate()).padStart(2, '0');
    const hours = String(vietnamTime.getUTCHours()).padStart(2, '0');
    const minutes = String(vietnamTime.getUTCMinutes()).padStart(2, '0');
    const seconds = String(vietnamTime.getUTCSeconds()).padStart(2, '0');
    return `${year}-${month}-${day} ${hours}:${minutes}:${seconds}`;
}

function parseDate(dateStr) {
    if (!dateStr || dateStr === '' || dateStr === 'Empty' || dateStr === 'Null') return null;
    const isoStr = dateStr.replace(' ', 'T') + '+07:00';
    const d = new Date(isoStr);
    return isNaN(d.getTime()) ? null : d;
}

// ============================================================
// ERROR CLASSIFICATION
// Maps error_code strings from callers to proper handling strategy
// ============================================================
const ERROR_STRATEGIES = {
    // === 429: RESOURCE_EXHAUSTED — Most dangerous ===
    'RATE_LIMIT': { type: 'rate_limit', blockMinutes: 15, shouldBlock: true },
    'RESOURCE_EXHAUSTED': { type: 'rate_limit', blockMinutes: 15, shouldBlock: true },
    'QUOTA_EXCEEDED': { type: 'rate_limit', blockMinutes: 60, shouldBlock: true },
    '429': { type: 'rate_limit', blockMinutes: 15, shouldBlock: true },

    // === 403: PERMISSION_DENIED — Key issue, long block ===
    'PERMISSION_DENIED': { type: 'auth', blockMinutes: 1440, shouldBlock: true },
    'FORBIDDEN': { type: 'auth', blockMinutes: 1440, shouldBlock: true },
    '403': { type: 'auth', blockMinutes: 1440, shouldBlock: true },

    // === 401: Invalid key — Very long block ===
    'INVALID_KEY': { type: 'auth', blockMinutes: 10080, shouldBlock: true },
    'UNAUTHENTICATED': { type: 'auth', blockMinutes: 10080, shouldBlock: true },
    '401': { type: 'auth', blockMinutes: 10080, shouldBlock: true },

    // === 400: Bad request — Not key's fault, transient ===
    'INVALID_ARGUMENT': { type: 'bad_request', blockMinutes: 0, shouldBlock: false },
    'BAD_REQUEST': { type: 'bad_request', blockMinutes: 0, shouldBlock: false },
    '400': { type: 'bad_request', blockMinutes: 0, shouldBlock: false },

    // === 404: Not found — Not key's fault ===
    'NOT_FOUND': { type: 'not_found', blockMinutes: 0, shouldBlock: false },
    '404': { type: 'not_found', blockMinutes: 0, shouldBlock: false },

    // === 500/503: Server errors — Transient, retry ===
    'INTERNAL': { type: 'server', blockMinutes: 0, shouldBlock: false },
    'SERVER_ERROR': { type: 'server', blockMinutes: 0, shouldBlock: false },
    '500': { type: 'server', blockMinutes: 0, shouldBlock: false },
    'UNAVAILABLE': { type: 'server', blockMinutes: 0, shouldBlock: false },
    'SERVICE_UNAVAILABLE': { type: 'server', blockMinutes: 0, shouldBlock: false },
    '503': { type: 'server', blockMinutes: 0, shouldBlock: false },

    // === Safety filter — Not key's fault ===
    'SAFETY': { type: 'safety', blockMinutes: 0, shouldBlock: false },
    'RECITATION': { type: 'safety', blockMinutes: 0, shouldBlock: false },
};

function classifyError(errorCode) {
    if (!errorCode) return null;
    const upper = errorCode.toUpperCase();

    // Check for exact match first
    for (const [key, strategy] of Object.entries(ERROR_STRATEGIES)) {
        if (upper.includes(key.toUpperCase())) return strategy;
    }

    // Check for HTTP status code pattern: "[429] ..." or "429:"
    const statusMatch = upper.match(/\[?(\d{3})\]?/);
    if (statusMatch) {
        const code = statusMatch[1];
        if (ERROR_STRATEGIES[code]) return ERROR_STRATEGIES[code];
    }

    return null; // Unknown error
}

// ============================================================
// QUOTA CONFIGS (New)
// ============================================================
const config = $("CONFIGS").first().json;
const LOW_REQUESTS_THRESHOLD = parseInt(config.LOW_REQUESTS_THRESHOLD || '100', 10);
const LOW_TOKENS_THRESHOLD = parseInt(config.LOW_TOKENS_THRESHOLD || '50000', 10);
const COOLDOWN_MINUTES = parseInt(config.COOLDOWN_MINUTES || '5', 10);
const MAX_CONSECUTIVE_FAILS = parseInt(config.MAX_CONSECUTIVE_FAILS || '3', 10);
const BLOCK_DURATION_HOURS = parseInt(config.BLOCK_DURATION_HOURS || '2', 10);

// ============================================================
// MAIN LOGIC
// ============================================================
const keyItems = $('Get Keys').all();
const now = new Date();

let triggerData = null;
try {
    const setNode = $('Webhook Set Key State');
    if (setNode && setNode.first() && setNode.first().json.body) {
        triggerData = setNode.first().json.body;
    }
} catch (e) { }

if (triggerData) {
    // ====================== SET KEY STATE (với rate_limit) ======================
    const { key_id, status, error_code, rate_limit } = triggerData;

    const keyItem = keyItems.find(i => i.json.key_id === key_id);
    if (!keyItem) throw new Error(`Key ${key_id} not found`);

    const key = { ...keyItem.json };
    const currentTime = getVietnamTime();
    key.last_used_at = currentTime;
    key.last_quota_check_at = currentTime;

    if (status === 'success') {
        key.last_success_at = currentTime;
        key.consecutive_failures = 0;
        key.blocked_until = '';
        key.error_code = '';
        key.health_status = 'healthy';
        key.is_active = true;

        // === TÍCH HỢP RATE LIMIT HEADERS ===
        if (rate_limit && typeof rate_limit === 'object') {
            key.remaining_requests = parseInt(rate_limit.remaining_requests || 0);
            key.remaining_tokens = parseInt(rate_limit.remaining_tokens || 0);
            key.quota_reset_requests_at = rate_limit.reset_requests || '';
            key.quota_reset_tokens_at = rate_limit.reset_tokens || '';
            key.retry_after = parseInt(rate_limit.retry_after || 0);

            // Nếu quota rất thấp → tự động mark low
            if (key.remaining_requests < LOW_REQUESTS_THRESHOLD || key.remaining_tokens < LOW_TOKENS_THRESHOLD) {
                key.health_status = 'rate_limited';
                const blockUntil = new Date(now.getTime() + 10 * 60 * 1000); // block nhẹ 10 phút
                key.blocked_until = getVietnamTime(blockUntil);
                key.is_active = false;
            }
        }
    } else if (status === 'fail') {
        key.last_failure_at = currentTime;
        key.error_code = error_code || 'UNKNOWN';

        // Classify the error to determine response strategy
        const strategy = classifyError(error_code);

        // Cập nhật quota nếu có trong fail response
        if (rate_limit) {
            key.remaining_requests = parseInt(rate_limit.remaining_requests || 0);
            key.remaining_tokens = parseInt(rate_limit.remaining_tokens || 0);
            // ... các trường quota khác nếu cần
        }

        if (strategy && strategy.shouldBlock) {
            // === IMMEDIATE BLOCK (429, 403, 401) ===
            const blockUntil = new Date(now.getTime() + strategy.blockMinutes * 60 * 1000);
            key.blocked_until = getVietnamTime(blockUntil);
            key.is_active = false;
            key.consecutive_failures = (parseInt(key.consecutive_failures) || 0) + 1;

            if (strategy.type === 'rate_limit') {
                key.health_status = 'rate_limited';
            } else {
                key.health_status = 'blocked';
            }

            console.log(`🔴 ${key_id}: ${strategy.type.toUpperCase()} → blocked ${strategy.blockMinutes}min until ${key.blocked_until}`);

        } else if (strategy && (strategy.type === 'server' || strategy.type === 'bad_request' || strategy.type === 'not_found' || strategy.type === 'safety')) {
            // === NOT KEY'S FAULT — don't punish the key ===
            key.health_status = 'degraded';
            console.log(`🟡 ${key_id}: ${strategy.type.toUpperCase()} → not key's fault, keeping active`);

        } else {
            // === UNKNOWN ERROR — use counter-based approach ===
            key.consecutive_failures = (parseInt(key.consecutive_failures) || 0) + 1;

            if (key.consecutive_failures >= MAX_CONSECUTIVE_FAILS) {
                const blockUntil = new Date(now.getTime() + BLOCK_DURATION_HOURS * 60 * 60 * 1000);
                key.blocked_until = getVietnamTime(blockUntil);
                key.is_active = false;
                key.health_status = 'blocked';
                console.log(`🔴 ${key_id}: UNKNOWN error × ${key.consecutive_failures} → blocked`);
            } else {
                key.health_status = 'degraded';
                console.log(`🟡 ${key_id}: UNKNOWN error × ${key.consecutive_failures}/${MAX_CONSECUTIVE_FAILS}`);
            }
        }
    }

    return { json: key };

} else {
    // ====================== GET ACTIVE KEY (với quota filter + sorting) ======================
    const allKeys = keyItems.map(item => ({ ...item.json }));

    const candidates = allKeys.filter(key => {
        if (!key.is_active) return false;
        if (!key.api_key || key.api_key.trim() === '') return false;

        const blockedUntil = parseDate(key.blocked_until);
        if (blockedUntil && blockedUntil > now) return false;

        if ((parseInt(key.consecutive_failures) || 0) >= MAX_CONSECUTIVE_FAILS) return false;

        // === PROACTIVE QUOTA FILTER ===
        const reqLeft = parseInt(key.remaining_requests) || 999999;
        const tokLeft = parseInt(key.remaining_tokens) || 999999999;
        if (reqLeft < LOW_REQUESTS_THRESHOLD || tokLeft < LOW_TOKENS_THRESHOLD) return false;

        // cooldown logic giữ nguyên...
        if (key.last_used_at && key.health_status !== 'degraded') {
            const lastUsed = parseDate(key.last_used_at);
            if (lastUsed) {
                const minutesAgo = (now - lastUsed) / 1000 / 60;
                if (minutesAgo < COOLDOWN_MINUTES) return false;
            }
        }
        return true;
    });

    if (candidates.length === 0) {
        throw new Error('No healthy API keys available (all blocked or quota low).');
    }

    // === SORTING MỚI: Ưu tiên quota cao nhất ===
    candidates.sort((a, b) => {
        if (a.priority !== b.priority) return a.priority - b.priority;

        // Health
        const healthPriority = { 'healthy': 0, 'recovered': 1, 'degraded': 2, 'rate_limited': 3 };
        const aH = healthPriority[a.health_status] || 4;
        const bH = healthPriority[b.health_status] || 4;
        if (aH !== bH) return aH - bH;

        // QUOTA – cao nhất ưu tiên
        const aTok = parseInt(a.remaining_tokens) || 0;
        const bTok = parseInt(b.remaining_tokens) || 0;
        if (aTok !== bTok) return bTok - aTok;   // cao → thấp

        // Never used / LRU giữ nguyên...
        const aNever = !a.last_used_at;
        const bNever = !b.last_used_at;
        if (aNever && !bNever) return -1;
        if (!aNever && bNever) return 1;

        const aTime = a.last_used_at ? (parseDate(a.last_used_at)?.getTime() || 0) : 0;
        const bTime = b.last_used_at ? (parseDate(b.last_used_at)?.getTime() || 0) : 0;
        return aTime - bTime;
    });

    const topCandidates = candidates.slice(0, Math.min(3, candidates.length));
    const selected = topCandidates[Math.floor(Math.random() * topCandidates.length)];

    const result = { ...selected };
    result.last_used_at = getVietnamTime();
    result.health_status = result.health_status || 'healthy';

    return { json: result };
}
